update campaign set 
    applicants_Num = #{applicantsNum} + 1
where campaign_id= #{campaignId}

mapper.select:

SELECT COUNT(*)
FROM user_campaign
WHERE user_no = #{userNo}
AND is_deleted = 'N'
AND (
    event_str_date <= #{eventPeriodEnd} 
    AND event_end_date >= #{eventPeriodStr}
)


SELECT c.campaign_title
FROM user_campaign uc
LEFT OUTER JOIN campaign c
ON uc.campaign_id = c.campaign_id
WHERE uc.user_no = #{userNo}
AND uc.is_deleted = 'N'
AND (
    uc.event_str_date <= #{eventPeriodEnd}
    AND uc.event_end_date >= #{eventPeriodStr}
)
LIMIT 1 -- 여러 개가 겹칠 수 있으니 가장 먼저 걸리는 것 하나만 가져옵니다
